import { getBasePath } from '../../utilities/base-path.js';
const fontSheet = new CSSStyleSheet();
let hasFontLoaded = false;
export const loadFont = () => {
    if (hasFontLoaded) {
        return;
    }
    hasFontLoaded = true;
    fontSheet.replaceSync(`
    @font-face {
      font-family: Geist;
      src: url(${getBasePath('/assets/fonts/Geist-VariableFont_wght.ttf')}) format('truetype');
      font-display: swap;
    }
    @font-face {
      font-family: 'Geist Mono';
      src: url(${getBasePath('/assets/fonts/GeistMono-VariableFont_wght.ttf')}) format('truetype');
      font-display: swap;
    } 
  `);
    document.adoptedStyleSheets.push(fontSheet);
};
